import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { NamedRegionRangeProvider } from '../../browser/namedRegionRangeProvider.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';
import { CancellationToken } from '../../../../../base/common/cancellation.js';

interface ExpectedNamedRegion {
	startLineNumber: number;
	endLineNumber: number;
	name: string;
}

function assertNamedRegions(lines: string[], expected: ExpectedNamedRegion[]): void {
	const model = createTextModel(lines.join('\n'));

	const foldingRangesLimit = { limit: 5000, update: () => { } };
	const provider = new NamedRegionRangeProvider(model, foldingRangesLimit);

	provider.compute(CancellationToken.None).then(regions => {
		const namedRegions = provider.getNamedRegions();

		const actualRegions: ExpectedNamedRegion[] = namedRegions.map(r => ({
			startLineNumber: r.startLineNumber,
			endLineNumber: r.endLineNumber,
			name: r.name
		}));

		assert.deepStrictEqual(actualRegions, expected);
		model.dispose();
	});
}

suite('Named Region Folding', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('Detect simple region', () => {
		const lines = [
			'// #region MyRegion',
			'const x = 1;',
			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ startLineNumber: 1, endLineNumber: 3, name: 'MyRegion' }
		]);
	});

	test('Detect region with C# style markers', () => {
		const lines = [
			'#region Implementation',
			'public void Method() {',
			'  // method body',
			'}',
			'#endregion'
		];
		assertNamedRegions(lines, [
			{ startLineNumber: 1, endLineNumber: 5, name: 'Implementation' }
		]);
	});

	test('Detect multiple regions', () => {
		const lines = [
			'// #region Header',
			'// Some comments',
			'// #endregion',
			'',
			'// #region Body',
			'const code = true;',
			'// #endregion',
			'',
			'// #region Footer',
			'// End comments',
			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ startLineNumber: 1, endLineNumber: 3, name: 'Header' },
			{ startLineNumber: 5, endLineNumber: 7, name: 'Body' },
			{ startLineNumber: 9, endLineNumber: 11, name: 'Footer' }
		]);
	});

	test('Detect nested regions', () => {
		const lines = [
			'// #region Outer',
			'// #region Inner',
			'const x = 1;',
			'// #endregion',
			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ startLineNumber: 1, endLineNumber: 5, name: 'Outer' },
			{ startLineNumber: 2, endLineNumber: 4, name: 'Inner' }
		]);
	});

	test('Detect region with whitespace and indentation', () => {
		const lines = [
			'  // #region   Indented   ',
			'    const x = 1;',
			'  // #endregion'
		];
		assertNamedRegions(lines, [
			{ startLineNumber: 1, endLineNumber: 3, name: 'Indented' }
		]);
	});

	test('Handle unclosed region (no endregion)', () => {
		const lines = [
			'// #region OpenRegion',
			'const x = 1;',
			'const y = 2;'
		];
		assertNamedRegions(lines, [
			{ startLineNumber: 1, endLineNumber: 3, name: 'OpenRegion' }
		]);
	});

	test('Ignore unmatched endregion', () => {
		const lines = [
			'const x = 1;',
			'// #endregion',
			'const y = 2;'
		];
		assertNamedRegions(lines, []);
	});

	test('Handle region with special characters in name', () => {
		const lines = [
			'// #region Feature-v1.0 (Implementation)',
			'const x = 1;',
			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ startLineNumber: 1, endLineNumber: 3, name: 'Feature-v1.0 (Implementation)' }
		]);
	});

	test('Empty region', () => {
		const lines = [
			'// #region Empty',
			'// #endregion'
		];
		assertNamedRegions(lines, [
			{ startLineNumber: 1, endLineNumber: 2, name: 'Empty' }
		]);
	});

	test('Return empty array when no regions found', () => {
		const lines = [
			'const x = 1;',
			'const y = 2;',
			'function foo() { }'
		];
		assertNamedRegions(lines, []);
	});
});

